import argparse
import json
import os
import pickle
from collections import defaultdict

import numpy as np
import gymnasium as gym
import humanoid_bench  # noqa: F401
from stable_baselines3 import PPO


TASKS = [
    "h1hand-walk-v0",
    "h1hand-stand-v0",
    "h1hand-run-v0",
    "h1hand-sit_simple-v0",
    "h1hand-balance_simple-v0",
    "h1hand-reach-v0",
    "h1hand-push-v0",
    "h1hand-pole-v0",
    "h1hand-door-v0",
    "h1hand-package-v0",
]


def resolve_eval_config(data_path: str) -> str:
    candidates = [
        os.path.join(data_path, "eval_config.json"),
        os.path.join(data_path, "humanoidbench_test", "eval_config.json"),
        os.path.join("/data", "eval_config.json"),
        os.path.join("/data", "humanoidbench_test", "eval_config.json"),
        os.path.join("local_eval", "eval_config.json"),
    ]
    for path in candidates:
        if os.path.exists(path):
            return path
    raise FileNotFoundError("Could not find eval_config.json")


def find_task_dir(checkpoint_root: str, task_id: str):
    candidates = [
        os.path.join(checkpoint_root, task_id),
        os.path.join(checkpoint_root, "per_task", task_id),
    ]
    for path in candidates:
        if os.path.isdir(path):
            return path
    return None


def resolve_model_path(task_dir: str) -> str:
    preferred = os.path.join(task_dir, "final_model")
    if os.path.exists(preferred) or os.path.exists(preferred + ".zip"):
        return preferred
    zips = sorted([x for x in os.listdir(task_dir) if x.endswith(".zip")])
    if not zips:
        raise FileNotFoundError(f"No checkpoint zip found in {task_dir}")
    return os.path.join(task_dir, zips[-1])


def load_vecnorm_stats(task_dir: str):
    path = os.path.join(task_dir, "vecnormalize.pkl")
    if not os.path.exists(path):
        return None
    with open(path, "rb") as f:
        obj = pickle.load(f)
    obs_rms = getattr(obj, "obs_rms", None)
    if obs_rms is None:
        return None
    return {
        "mean": np.asarray(obs_rms.mean, dtype=np.float32),
        "var": np.asarray(obs_rms.var, dtype=np.float32),
        "clip_obs": float(getattr(obj, "clip_obs", 10.0)),
        "epsilon": float(getattr(obj, "epsilon", 1e-8)),
    }


def load_meta(task_dir: str):
    path = os.path.join(task_dir, "meta.json")
    if not os.path.exists(path):
        return {}
    with open(path, "r") as f:
        return json.load(f)


def normalize_obs(obs, stats):
    x = np.asarray(obs, dtype=np.float32)
    if stats is None:
        return x
    mean = stats["mean"]
    var = stats["var"]
    if x.shape != mean.shape:
        return x
    x = (x - mean) / np.sqrt(var + stats["epsilon"])
    x = np.clip(x, -stats["clip_obs"], stats["clip_obs"])
    return x.astype(np.float32)


def load_policy_bundle(checkpoint_root: str, task_id: str, obs_dim: int, cache: dict):
    if task_id in cache:
        return cache[task_id]

    task_dir = find_task_dir(checkpoint_root, task_id)
    if task_dir is None:
        bundle = {"kind": "zero", "task_id": task_id, "obs_dim": obs_dim}
        cache[task_id] = bundle
        return bundle

    meta = load_meta(task_dir)
    meta_obs = None
    if isinstance(meta.get("obs_space"), list) and len(meta["obs_space"]) >= 1:
        meta_obs = int(meta["obs_space"][0])

    stats = load_vecnorm_stats(task_dir)
    stats_obs = None if stats is None else int(stats["mean"].shape[0])
    expected_obs = meta_obs if meta_obs is not None else stats_obs

    if expected_obs is not None and expected_obs != int(obs_dim):
        bundle = {"kind": "zero", "task_id": task_id, "obs_dim": obs_dim}
        cache[task_id] = bundle
        return bundle

    model = PPO.load(resolve_model_path(task_dir), device="cpu")
    bundle = {
        "kind": "ppo",
        "task_id": task_id,
        "obs_dim": obs_dim,
        "model": model,
        "stats": stats,
    }
    cache[task_id] = bundle
    return bundle


def predict_action(bundle, obs, action_space):
    if bundle["kind"] == "zero":
        return np.zeros(action_space.shape, dtype=np.float32)
    model_obs = normalize_obs(obs, bundle.get("stats"))
    action, _ = bundle["model"].predict(model_obs, deterministic=True)
    action = np.asarray(action, dtype=np.float32)
    action = np.clip(action, action_space.low, action_space.high)
    return action


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--data_path", required=True)
    ap.add_argument("--checkpoint", required=True)
    ap.add_argument("--output", required=True)
    args = ap.parse_args()

    cfg_path = resolve_eval_config(args.data_path)
    with open(cfg_path, "r") as f:
        cfg = json.load(f)

    cache = {}
    per_episode = []

    for task_spec in cfg["tasks"]:
        task_id = task_spec["task_id"]
        obs_dim = int(task_spec["obs_dim"])
        max_steps = int(task_spec["max_episode_steps"])
        success_bar = float(task_spec["success_bar"])
        info_has_success = bool(task_spec.get("info_has_success", False))

        bundle = load_policy_bundle(args.checkpoint, task_id, obs_dim, cache)

        for ep_idx, seed in enumerate(task_spec["seeds"]):
            env = gym.make(task_id)
            obs, _ = env.reset(seed=int(seed))
            ep_reward = 0.0
            ep_info_success = 0

            for _step in range(max_steps):
                action = predict_action(bundle, obs, env.action_space)
                obs, reward, terminated, truncated, info = env.step(action)
                ep_reward += float(reward)
                if info_has_success and int(info.get("success", 0)) > 0:
                    ep_info_success = 1
                if terminated or truncated:
                    break
            env.close()

            ep_success = int(ep_reward >= success_bar)
            if info_has_success:
                ep_success = max(ep_success, ep_info_success)

            per_episode.append({
                "task_id": task_id,
                "episode_id": ep_idx,
                "seed": int(seed),
                "reward": round(ep_reward, 4),
                "success": int(ep_success),
            })

    tk_n, tk_s, tk_r = defaultdict(int), defaultdict(int), defaultdict(float)
    for ep in per_episode:
        tk_n[ep["task_id"]] += 1
        tk_s[ep["task_id"]] += ep["success"]
        tk_r[ep["task_id"]] += ep["reward"]

    per_task = {
        t: {
            "success_rate": tk_s[t] / max(tk_n[t], 1),
            "mean_reward": tk_r[t] / max(tk_n[t], 1),
            "n_episodes": tk_n[t],
        }
        for t in tk_n
    }

    results = {
        "success_rate": sum(ep["success"] for ep in per_episode) / max(len(per_episode), 1),
        "mean_reward": sum(ep["reward"] for ep in per_episode) / max(len(per_episode), 1),
        "total_episodes": len(per_episode),
        "per_task": per_task,
        "per_episode": per_episode,
    }

    os.makedirs(os.path.dirname(args.output) or ".", exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(results, f)


if __name__ == "__main__":
    main()
